window.COURSE_LANG = window.COURSE_LANG || {};
window.COURSE_LANG["manicurist"] = window.COURSE_LANG["manicurist"] || {};
window.COURSE_LANG["manicurist"]["es"] = [
  {"id":1,"q":"Antes de poder desinfectar un implemento metálico de uñas, primero hay que:","opts":["Calentarlo bajo una lámpara","Limpiarlo con agua y jabón para quitar todos los residuos visibles","Envolverlo en una toalla de papel","Rociarlo con aceite para cutículas"],"re":"El desinfectante solo funciona en una superficie limpia; los residuos visibles deben lavarse con agua y jabón antes de sumergir."},
  {"id":2,"q":"Para usarse en un salón de uñas de California, un desinfectante debe estar:","opts":["Registrado con la EPA de EE. UU. y etiquetado como bactericida, fungicida y virucida","Cualquier aerosol doméstico perfumado","Solo alcohol para frotar","Mezclado por el dueño sin etiqueta"],"re":"California exige un desinfectante de grado hospitalario registrado por la EPA cuya etiqueta muestre actividad bactericida, fungicida y virucida."},
  {"id":3,"q":"Los implementos metálicos reutilizables, como alicates y empujadores, se desinfectan mediante:","opts":["Limpiarlos con una toalla","Enjuagarlos bajo agua corriente","Inmersión total en un desinfectante bien mezclado durante el tiempo de la etiqueta","Dejarlos al sol"],"re":"Los implementos no eléctricos deben sumergirse por completo en el desinfectante registrado por la EPA y bien mezclado durante el tiempo de contacto indicado."},
  {"id":4,"q":"Un palillo de naranjo de madera o una lima de un solo uso debe:","opts":["Desinfectarse y reutilizarse con el próximo cliente","Limpiarse con alcohol y reutilizarse","Hervirse y reutilizarse","Usarse con un solo cliente y luego desecharse o entregarse a ese cliente"],"re":"Los artículos porosos de un solo uso no pueden desinfectarse; se desechan después de un cliente o se le entregan a ese cliente."},
  {"id":5,"q":"Después de cada cliente, un spa de pies sin tubería para pedicura debe tener desinfectante circulando durante al menos:","opts":["10 segundos","2 minutos","10 minutos","No se requiere tiempo"],"re":"Las reglas de California exigen circular la cantidad correcta de desinfectante registrado por la EPA por la cubeta durante al menos 10 minutos después de cada cliente."},
  {"id":6,"q":"Una caja de luz UV en un salón de uñas puede usarse correctamente para:","opts":["Desinfectar implementos en lugar de usar químicos","Esterilizar las herramientas por completo","Guardar implementos que ya fueron limpiados y desinfectados","Matar todos los virus al contacto"],"re":"Las cajas UV no desinfectan ni esterilizan de forma confiable; solo sirven para guardar herramientas que ya fueron limpiadas y desinfectadas."},
  {"id":7,"q":"Los implementos desinfectados deben guardarse en:","opts":["Un recipiente limpio y cubierto, separado de los artículos sucios","El mismo cajón que las herramientas usadas","Un plato abierto sobre la mesa","Un bolsillo con implementos sucios"],"re":"Las herramientas limpias y desinfectadas deben mantenerse en un lugar limpio y cubierto, separadas de los implementos usados o sucios."},
  {"id":8,"q":"Un técnico de uñas debe lavarse las manos:","opts":["Solo al final del día","Solo cuando las manos se ven sucias","Antes y después de atender a cada cliente","Una vez por semana"],"re":"Lavarse las manos antes y después de cada cliente es un paso básico y esencial para evitar la propagación de infecciones."},
  {"id":9,"q":"¿Qué proceso destruye toda vida microbiana, incluidas las esporas bacterianas?","opts":["Sanitizar con una toallita","Enjuagar con agua","Quitar el polvo de la mesa","La esterilización, por ejemplo con una autoclave"],"re":"La esterilización, por ejemplo en una autoclave, mata todos los microorganismos incluidas las esporas; es el nivel más alto de descontaminación."},
  {"id":10,"q":"La parte de la unidad de la uña donde se producen las células nuevas es la:","opts":["Matriz","Borde libre","Hiponiquio","Lúnula"],"re":"La matriz es el área viva y reproductiva donde se forman las células de la uña; dañarla puede deformar la lámina ungueal."},
  {"id":11,"q":"La media luna blanquecina visible en la base de la uña es la:","opts":["Borde libre","Lúnula","Eponiquio","Lecho ungueal"],"re":"La lúnula es la media luna blanquecina, la parte de la matriz visible a través de la lámina de la uña."},
  {"id":12,"q":"La porción de la lámina ungueal que se extiende más allá de la punta del dedo es el:","opts":["Matriz","Cutícula","Borde libre","Pliegue ungueal"],"re":"El borde libre es la parte de la lámina que crece más allá de la punta del dedo y que se lima y se le da forma."},
  {"id":13,"q":"La piel viva en la base de la lámina ungueal de la cual se desprende la cutícula es el:","opts":["Hiponiquio","Borde libre","Lúnula","Eponiquio"],"re":"El eponiquio es la piel viva en la base de la lámina ungueal; la cutícula es el tejido muerto que esta desprende sobre la lámina."},
  {"id":14,"q":"La piel ligeramente engrosada bajo el borde libre, donde se une con la punta del dedo, es el:","opts":["Hiponiquio","Matriz","Lúnula","Pared ungueal"],"re":"El hiponiquio es la piel bajo el borde libre que sella y protege el lecho ungueal de los contaminantes."},
  {"id":15,"q":"Una afección como la onicomicosis (un hongo en la uña) es una enfermedad de la uña, lo que significa que el técnico debe:","opts":["Atenderla con normalidad","Cortarla para quitar la infección","No realizar el servicio y remitir al cliente a un médico","Aplicar una capa de gel para sellarla"],"re":"Una infección o enfermedad está fuera del alcance de un manicurista; no la atienda y remita al cliente a un médico."},
  {"id":16,"q":"La infección bacteriana del tejido alrededor de la uña, a menudo roja, hinchada y sensible, se llama:","opts":["Leuconiquia","Onicólisis","Pterigión","Paroniquia"],"re":"La paroniquia es una infección bacteriana o por levadura de los pliegues de piel alrededor de la uña; debe remitirse, no atenderse."},
  {"id":17,"q":"El levantamiento o separación de la lámina ungueal del lecho, que suele comenzar en el borde libre, es:","opts":["Onicólisis","Un padrastro","Leuconiquia","Onicofagia"],"re":"La onicólisis es la separación de la lámina respecto al lecho; manéjela con suavidad y remita si se sospecha infección u otra enfermedad."},
  {"id":18,"q":"Las manchas blancas en la lámina ungueal, por lo general causadas por una lesión leve de la matriz, se llaman:","opts":["Onicólisis","Pterigión","Leuconiquia","Paroniquia"],"re":"La leuconiquia son manchas blanquecinas por un traumatismo leve de la matriz; es inofensiva y puede atenderse con normalidad."},
  {"id":19,"q":"En promedio, una uña sana de la mano crece aproximadamente:","opts":["1 pulgada por semana","2 pulgadas por mes","No crece una vez formada","Hasta cerca de 1/8 de pulgada (3 mm) por mes"],"re":"Una uña normal de la mano crece alrededor de 1/8 de pulgada (unos 3 mm) al mes, algo más rápido en verano y en la mano dominante."},
  {"id":20,"q":"Durante una manicura básica, la zona de la cutícula debe:","opts":["Cortarse profundamente para quitar toda la piel","Empujarse con suavidad, sin cortar nunca el tejido vivo","Dejarse totalmente intacta en todo momento","Limarse con un abrasivo grueso"],"re":"La cutícula ablandada se empuja con suavidad; cortar la piel viva puede causar lesiones e infecciones."},
  {"id":21,"q":"Al limar una uña natural, se debe:","opts":["Limar de un lado a otro de forma agresiva","Limar de la esquina al centro en una sola dirección con pasadas suaves","Usar la lima más gruesa disponible","Limar solo la parte de abajo de la uña"],"re":"Limar de la esquina hacia el centro en una sola dirección evita que la uña natural se astille o se debilite."},
  {"id":22,"q":"La forma que se considera más resistente para una uña natural porque sigue la punta del dedo es la:","opts":["Forma puntiaguda (stiletto)","Forma extremadamente larga","Ninguna forma importa para la resistencia","Forma cuadrada o cuadrada-ovalada (squoval)"],"re":"Una forma cuadrada o squoval deja más uña en los puntos de tensión, lo que la hace más duradera que las formas puntiagudas."},
  {"id":23,"q":"En una pedicura, la piel con callosidad en el pie debe:","opts":["Cortarse con una navaja u hoja credo","Suavizarse con una lima de pies o piedra pómez, sin cortar con hoja","Dejarse intacta en todos los casos","Quitarse con ácido fuerte"],"re":"Los manicuristas suavizan las callosidades con una lima de pies o piedra pómez; cortar la piel con una hoja credo o navaja está prohibido."},
  {"id":24,"q":"Durante una pedicura, las uñas de los pies deben cortarse y limarse:","opts":["Rectas para ayudar a prevenir uñas encarnadas","Muy redondeadas en las esquinas","En punta filosa","Hacia adentro del surco de la uña"],"re":"Cortar las uñas de los pies en línea recta reduce el riesgo de uñas encarnadas, a diferencia de redondear mucho las esquinas."},
  {"id":25,"q":"Un tratamiento de cera de parafina se usa principalmente para:","opts":["Desinfectar las manos","Quitar el esmalte en gel","Suavizar e hidratar la piel con calor suave","Endurecer la uña natural"],"re":"La parafina tibia aporta calor suave y retiene la humedad, suavizando y acondicionando la piel de las manos o los pies."},
  {"id":26,"q":"El masaje durante una manicura o pedicura debe evitarse cuando el cliente tiene:","opts":["Piel un poco seca","Esmalte recién pintado","Flebitis, un coágulo de sangre u otra afección circulatoria","Preferencia por uñas cortas"],"re":"El masaje puede desprender un coágulo o agravar un problema circulatorio; evítelo y remita al cliente a un médico ante la duda."},
  {"id":27,"q":"El orden correcto de una manicura básica generalmente es:","opts":["Esmaltar, luego quitar el esmalte, luego limar","Dar forma y limar, ablandar y atender cutículas, y aplicar el esmalte al final","Aplicar la capa superior primero, luego la base","Solo masaje, sin cuidado de la uña"],"re":"Una manicura va de quitar el esmalte viejo y dar forma, al cuidado de cutículas y masaje, terminando con base, color y capa superior."},
  {"id":28,"q":"Un pinchazo que saca unas gotas de sangre del cliente significa que primero debe:","opts":["Seguir trabajando e ignorarlo","Limpiarlo con una toalla compartida","Continuar con el mismo implemento sin desinfectar","Detener el servicio y ponerse guantes antes de manipular la sangre"],"re":"Detente de inmediato y ponte guantes antes de tocar la sangre; luego limpia y desinfecta o desecha el implemento contaminado."},
  {"id":29,"q":"Una uña acrílica tradicional (esculpida) se forma a partir de:","opts":["Un monómero líquido combinado con un polímero en polvo","Savia de árbol curada","Solo capa superior (top coat)","Algodón y agua"],"re":"Las uñas acrílicas se hacen mezclando un monómero líquido con un polímero en polvo, que se endurece al polimerizar."},
  {"id":30,"q":"Una uña de gel UV o LED se endurece mediante un proceso llamado:","opts":["Evaporación del agua","Congelación","Secado al aire como el esmalte de uñas","Curado (polimerización) activado por la luz de una lámpara"],"re":"Los geles contienen fotoiniciadores que inician la polimerización, así que el gel solo cura al exponerse a la luz UV o LED de la lámpara."},
  {"id":31,"q":"Una envoltura (wrap) de uña refuerza o repara una uña usando:","opts":["Una placa de metal","Una tela como seda o fibra de vidrio adherida con pegamento","Un imán","Una gota de agua"],"re":"Las envolturas usan una tela como seda o fibra de vidrio adherida con resina para fortalecer o reparar la uña."},
  {"id":32,"q":"A medida que crece la uña natural, el espacio entre la extensión y la cutícula que debe mantenerse se llama:","opts":["Borde libre","Lúnula","Zona de relleno (rebalanceo)","Hiponiquio"],"re":"El espacio que crece se llena durante un relleno o rebalanceo para que la extensión quede pareja y bien adherida."},
  {"id":33,"q":"Antes de aplicar una extensión, la uña natural debe:","opts":["Limarse hasta dejarla muy delgada como papel","Limpiarse y prepararse ligeramente, quitando solo el brillo de la superficie","Limarse de forma agresiva con torno hacia el lecho","Cubrirse con aceite de cutículas para agarre"],"re":"Una preparación ligera que solo quita el brillo de la superficie ayuda a la adherencia; limar de más o usar torno adelgaza y daña la uña natural."},
  {"id":34,"q":"El levantamiento de una extensión en los bordes es un problema sobre todo porque:","opts":["Se ve brillante","Atrapa humedad y permite que crezcan bacterias u hongos debajo","Hace la uña demasiado fuerte","Cura el gel más rápido"],"re":"Una bolsa levantada atrapa humedad y residuos, creando un lugar donde puede desarrollarse una infección bacteriana o por hongos."},
  {"id":35,"q":"Para quitar un esmalte en gel soak-off, normalmente se:","opts":["Levanta con un empujador de metal","Arranca rápido con la uña natural","Calienta con llama abierta","Remoja en acetona para ablandarlo y luego se retira con suavidad"],"re":"Los geles soak-off se ablandan en acetona y se retiran con suavidad; levantarlos o pelarlos arranca capas de la uña natural."},
  {"id":36,"q":"Al aplicar producto de extensión, se debe evitar que toque la piel de alrededor porque:","opts":["Cambia el color","El contacto repetido con la piel puede causar sobreexposición y una reacción alérgica","Cura demasiado lento sobre la piel","Hace la uña más corta"],"re":"Mantener el producto fuera de la piel evita el contacto repetido que lleva a la sobreexposición, la sensibilización y la dermatitis alérgica."},
  {"id":37,"q":"Una extensión aplicada demasiado gruesa tiende a:","opts":["Durar más sin ninguna desventaja","Curar mejor bajo la lámpara","Proteger la matriz","Verse poco natural y ser más propensa a levantarse y agrietarse"],"re":"El producto aplicado demasiado grueso se ve voluminoso y es más propenso a levantarse, agrietarse o saltarse que una capa fina y equilibrada."},
  {"id":38,"q":"SDS significa:","opts":["Hoja de Datos de Seguridad (Safety Data Sheet)","Estándar de Desinfección del Salón","Horario Diario Estándar","Hoja de Tareas de Sanitización"],"re":"Una SDS es una Hoja de Datos de Seguridad, el documento que describe los peligros, el manejo y las medidas de primeros auxilios de un producto."},
  {"id":39,"q":"La forma más importante de reducir la sobreexposición a vapores y polvos de productos de uñas es:","opts":["Cerrar todas las ventanas","Buena ventilación, con los productos tapados y el polvo controlado","Encender una vela","Trabajar a oscuras"],"re":"Una buena ventilación reduce los niveles de vapor y polvo; mantener los recipientes tapados y controlar las limaduras reduce lo que se respira."},
  {"id":40,"q":"El \"trío tóxico\" de químicos de preocupación en productos de uñas se refiere a:","opts":["Tolueno, formaldehído y ftalato de dibutilo (DBP)","Agua, oxígeno y sal","Azúcar, almidón y harina","Hierro, cobre y zinc"],"re":"El \"trío tóxico\" es tolueno, formaldehído y ftalato de dibutilo (DBP), antes comunes en algunos productos de uñas."},
  {"id":41,"q":"La acetona y muchos productos de uñas son inflamables, por lo que deben guardarse lejos de:","opts":["Toallas limpias","La lista de precios","Solo la luz del día","Calor, chispas y llama abierta"],"re":"La acetona y productos similares son inflamables y deben mantenerse lejos del calor, las chispas y la llama abierta."},
  {"id":42,"q":"Cada botella y recipiente de químicos en la estación de uñas debe estar:","opts":["Sin etiqueta","Marcado solo con un color de calcomanía","Claramente etiquetado para identificar su contenido","Guardado junto a una llama abierta"],"re":"Todos los recipientes de químicos deben estar etiquetados para que cualquiera pueda identificar el contenido y los peligros."},
  {"id":43,"q":"Una reacción alérgica a los productos de uñas (dermatitis alérgica de contacto) por lo general:","opts":["Ocurre al instante en el primer contacto cada vez","Solo afecta al cliente, nunca al técnico","Se desarrolla con exposiciones repetidas y puede aparecer como piel roja, con picazón y agrietada","No puede prevenirse en absoluto"],"re":"La sensibilización se acumula con el contacto repetido con la piel y luego aparece como enrojecimiento, picazón o grietas; evitar el contacto la previene."},
  {"id":44,"q":"Si un químico fuerte salpica el ojo del cliente o el tuyo, debes:","opts":["Enjuagar el ojo con agua y seguir la guía de primeros auxilios de la SDS","Frotar el ojo con fuerza","Aplicar más producto","Ignorarlo"],"re":"Enjuaga el ojo con agua y sigue las instrucciones de primeros auxilios de la SDS, buscando ayuda médica en exposiciones graves."},
  {"id":45,"q":"En los salones con licencia de California, el monómero metacrilato de metilo (MMA) está:","opts":["Requerido para todos los acrílicos","Es lo mismo que la acetona","Solo se usa en uñas de los pies","Prohibido para usarse en las uñas"],"re":"El MMA está prohibido en los salones con licencia de California porque puede causar daño y reacciones alérgicas; los acrílicos legítimos usan EMA en su lugar."},
  {"id":46,"q":"La Junta de Barbería y Cosmetología de California opera bajo el:","opts":["OSHA federal","Departamento de Asuntos del Consumidor","Servicio Postal de EE. UU.","Departamento de Agricultura"],"re":"La Junta forma parte del Departamento de Asuntos del Consumidor de California, que supervisa los programas de licencias."},
  {"id":47,"q":"Las reglas de California exigen un registro de limpieza del spa de pies para pedicura que anote:","opts":["La fecha, la hora y las iniciales de quien limpió la cubeta","Nada en particular","Las propinas del cliente","Los totales de ventas al por menor"],"re":"El registro requerido del equipo de pedicura documenta cada limpieza con la fecha, la hora y las iniciales de quien la realizó."},
  {"id":48,"q":"Una licencia de manicurista de California por lo general debe renovarse:","opts":["Cada 6 meses","Una vez y nunca más","Cada dos años","Solo cuando te mudas"],"re":"Las licencias de California, incluida la de manicurista, se renuevan en un ciclo de dos años."},
  {"id":49,"q":"Usar una hoja credo o navaja para cortar piel o callosidades en el pie del cliente está:","opts":["Requerido en toda pedicura","Prohibido en California","Permitido solo en el talón","Recomendado para callosidades gruesas"],"re":"Cortar la piel con una hoja credo o navaja está prohibido; las callosidades se suavizan con una lima o piedra pómez."},
  {"id":50,"q":"Durante una inspección de la Junta a un salón de uñas, un inspector probablemente revise que:","opts":["Se cumplan las reglas de desinfección y sanitización","Esté sonando la música","Las sillas sean de cierto color","El dueño sea amable"],"re":"Los inspectores verifican el cumplimiento de los requisitos de sanitización y desinfección, de las áreas de violación más citadas."}
];
